const action = $input.first().json.action;
let url = '';
let method = '';
let body = {};

switch (action) {
  case 'clear':
    method='DELETE';
    url='https://lightrag.bigalexn8n.ru/documents';
    break;
  case 'insertText':
    method='POST';
    url='https://lightrag.bigalexn8n.ru/documents/text';
    body.text = $input.first().json.text;
    body.file_source = $input.first().json.meta_data;
    break;
  case 'deleteChunks':
    method='DELETE';
    url='https://lightrag.bigalexn8n.ru/documents/delete_document';
    body.doc_ids = [];
    body.delete_file = true;
    body.delete_llm_cache = true;
    break;
  case 'insertTexts':
    method='POST';
    url='https://lightrag.bigalexn8n.ru/documents/texts';
    body.texts = $input.first().json.texts;
    body.file_sources = JSON.parse($input.first().json.meta_data);
    break;
  case 'query':
    method='POST';
    url='https://lightrag.bigalexn8n.ru/query';
    body.query=`Проанализируй корейский текст ниже. Найди в базе знаний факты о персонажах, их поле, локациях и терминах.

### ПРАВИЛА ОФОРМЛЕНИЯ СПРАВКИ:
1. Важно: ВСЕ имена и названия должны быть ТОЛЬКО на русском языке. 
2. Если есть имя на корейском языке - транслитерируй его на русский язык самостоятельно (например, 이사영 -> И Саён). 
3. НЕ оставляй корейских символов в итоговом списке.
4. Объединяй все факты об одном персонаже в один пункт.
5. НЕ пиши фразы типа 'персонаж, к которому относится имя'. Пиши сразу суть.
6. Если факта нет - не выдумывай, исключи из ответа

### ФОРМАТ ОТВЕТА (СПИСОК):
 - [Имя]: [пол, краткая роль и характеристика]
 - [Связь]: [отношения между героями на русском]
 - [Факт]: [событие на русском]
 - [Локация]: [описание локации]`;
    body.mode = "mix";
    body.top_k = 20;
    body.max_total_tokens = 1500;
    body.response_type = 'Single Paragraph';
    body.user_prompt = `Текст:
    ${$input.first().json.text}`;
    break;
  case 'summary':
    method='POST';
    url='https://lightrag.bigalexn8n.ru/query';
    body.mode = "global";
    body.top_k = 40;
    body.max_total_tokens = 4000;
    body.response_type = 'Single Paragraph';
    body.query = `### ЗАДАЧА: СИНТЕЗ СУТИ КНИГИ
Проанализируй ВЕСЬ граф знаний этой книги. Игнорируй мелкие диалоги и временные события. 
Выдели глобальную структуру сюжета и ключевые образы.

### ЧТО НУЖНО ВЫДЕЛИТЬ:
1. КЛЮЧЕВАЯ КОНЦЕПЦИЯ: В чем главная идея мира? (Например: система уровней в реальности, месть падшего бога, выживание в космосе).
2. ГЛАВНЫЕ ГЕРОИ (АРХЕТИП): Краткое описание личности героев и их главные визуальные особенности (шрам, глаза, броня). Количество героев: 1 или 2.
3. ГЛАВНЫЙ КОНФЛИКТ: Против чего или кого сражается мир или герои?
4. КЛЮЧЕВАЯ ЛОКАЦИЯ: Где происходит основное действие, задающее атмосферу?
5. ЦВЕТОВАЯ ПАЛИТРА И СТИЛЬ: Какое настроение у этой истории? (Мрачное, золотое, неоновое, кровавое).

ВЫДАЙ ОТВЕТ СТРОГО СПИСКОМ ТЕЗИСОВ НА РУССКОМ ЯЗЫКЕ. 
Минимум воды, максимум смысла.
`;
    break;
  default:
    break;
}
return {url, method, body}
